class Solution:
    def canConstruct(self, s: str, k: int) -> bool:
        if len(s) < k:
            return False
        freq = {}
        for c in s:
            freq[c] = freq.get(c, 0) + 1
        odd_count = sum(1 for v in freq.values() if v % 2 == 1)
        return odd_count <= k

