class Solution:
    def canConstruct(self, s: str, k: int) -> bool:
        if len(s) < k:
            return False
        odd_count = 0
        seen = 0
        for c in s:
            bit = 1 << (ord(c) - ord('a'))
            if seen & bit:
                seen &= ~bit
                odd_count -= 1
            else:
                seen |= bit
                odd_count += 1
        return odd_count <= k

