var canConstruct = function(s, k) {
    if (s.length < k) return false;
    const freq = new Array(26).fill(0);
    for (const c of s) freq[c.charCodeAt(0) - 97]++;
    const oddCount = freq.filter(v => v % 2 === 1).length;
    return oddCount <= k;
};
